def get_all_fails():
    """Return all open failing trades."""
    return [f for f in FAIL_QUEUE if f["status"] in ("OPEN", "PARTIAL")]


def get_fail_by_id(fail_id: str):
    return next((f for f in FAIL_QUEUE if f["fail_id"] == fail_id), None)


def get_critical_fails():
    from datetime import date
    today = str(date.today())
    return [f for f in get_all_fails() if f["rule204_deadline"] <= today]


def get_fails_by_counterparty(counterparty: str):
    return [f for f in get_all_fails() if f["counterparty"] == counterparty]
